USE campus_security;

UPDATE sys_course SET quiz = '[{"question": "发现宿舍起火，首先应该做什么？", "options": ["自己尝试扑灭，不告诉别人", "拨打119并安全撤离", "先去抢救贵重物品", "躲在衣柜里等待救援"], "answer": 1}]' WHERE id = 1;
UPDATE sys_course SET quiz = '[{"question": "在校园内骑车，以下哪种行为是正确的？", "options": ["双手脱把", "边骑车边看手机", "靠右侧行驶，注意避让行人", "在人群中穿梭炫技"], "answer": 2}]' WHERE id = 2;
UPDATE sys_course SET quiz = '[{"question": "遇到自称警察要求转账到安全账户的电话，应该？", "options": ["立刻按要求转账", "挂断并拨打110核实或报警", "告诉对方自己没钱", "添加对方微信详细了解"], "answer": 1}]' WHERE id = 3;
UPDATE sys_course SET quiz = '[{"question": "强酸溅到皮肤上，正确的初步处理方法是？", "options": ["用纸巾擦干", "立即用大量流动清水冲洗至少15分钟", "涂抹红霉素软膏", "用热水清洗"], "answer": 1}]' WHERE id = 4;
UPDATE sys_course SET quiz = '[{"question": "当发现身边同学有严重抑郁和轻生倾向时，应该？", "options": ["觉得他只是开玩笑，不用理会", "跟着他一起悲观", "及时向辅导员或心理健康中心报告", "在朋友圈公开嘲笑他"], "answer": 2}]' WHERE id = 5;
UPDATE sys_course SET quiz = '[{"question": "离开宿舍时，最基本的防盗措施是？", "options": ["不锁门，方便室友进出", "随手锁门", "把贵重物品放在显眼处", "在门上贴纸条说屋里没人"], "answer": 1}]' WHERE id = 6;